customFusionChartConfig:
{
  "type": "mscombidy2d",
  "dataSource": {
    "dataset": [
      {
        "seriesname": "Upgrade Cancellations",
        "renderAs": "column",
        "color": "#f28c28",
        "data": {{ (() => { const rows = Array.isArray(UpgradeCancellationsbyMo.data) ? UpgradeCancellationsbyMo.data : []; return rows.map((row) => ({ value: row.subscriptions, color: Color.getRandomColor('#f28c28') })); })() }}
      },
      {
        "seriesname": "MRR Impact",
        "renderAs": "line",
        "parentyaxis": "S",
        "color": "#1B2E43",
        "data": {{ (() => { const rows = Array.isArray(UpgradeCancellationsbyMo.data) ? UpgradeCancellationsbyMo.data : []; return rows.map((row) => ({ value: row.mrr })); })() }}
      }
    ],
    "categories": [
      {
        "category": {{ (() => { const rows = Array.isArray(UpgradeCancellationsbyMo.data) ? UpgradeCancellationsbyMo.data : []; return rows.map((row) => ({ label: row.month })); })() }}
      }
    ],
    "chart": {
      "caption": "Upgrade Cancellations (Monthly)",
      "xAxisName": "Month",
      "yAxisName": "Subscriptions",
      "sYAxisName": "MRR",
      "sNumberPrefix": "$",
      "theme": "fusion",
      "paletteColors": "#17a2b8",
      "baseFont": "Roboto, sans-serif",
      "baseFontSize": "14",
      "baseFontColor": "#4d4d4d",
      "captionFont": "Roboto, sans-serif",
      "captionFontSize": "24",
      "subCaptionFont": "Roboto, sans-serif",
      "subCaptionFontSize": "18",
      "subCaptionFontColor": "#868e96",
      "anchorBgColor": "#1B2E43",
      "anchorBgHoverColor": "#1B2E43",
      "anchorHoverRadius": "7",
      "labelFontColor": "#888"
    }
  }
}
